{
  description = "Shun Kakinoki's Nix Configuration";

  inputs = {
    nixpkgs-stable = {
      url = "github:NixOS/nixpkgs/nixos-24.11";
    };
    nixpkgs-unstable = {
      url = "github:NixOS/nixpkgs/nixpkgs-unstable";
    };
    nixpkgs-nightly = {
      url = "github:NixOS/nixpkgs/master";
    };
    nixpkgs = {
      follows = "nixpkgs-unstable";
    };
    home-manager = {
      url = "github:nix-community/home-manager";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    nur = {
      url = "github:nix-community/NUR";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    nix-darwin = {
      url = "github:LnL7/nix-darwin";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    flake-parts = {
      url = "github:hercules-ci/flake-parts";
    };
    treefmt-nix = {
      url = "github:numtide/treefmt-nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    agenix = {
      url = "github:ryantm/agenix";
      inputs.nixpkgs.follows = "nixpkgs";
      inputs.home-manager.follows = "home-manager";
    };
    neovim-nightly-overlay = {
      url = "github:nix-community/neovim-nightly-overlay";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    devenv = {
      url = "github:cachix/devenv";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    foundry = {
      url = "github:shazow/foundry.nix";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    mk-shell-bin = {
      url = "github:rrbutani/nix-mk-shell-bin";
    };
    nix2container = {
      url = "github:nlewo/nix2container";
      inputs.nixpkgs.follows = "nixpkgs";
    };
    nixos-hardware = {
      url = "github:NixOS/nixos-hardware/master";
    };
    xremap = {
      url = "github:xremap/nix-flake";
      inputs.nixpkgs.follows = "nixpkgs";
    };
  };

  outputs =
    {
      flake-parts,
      treefmt-nix,
      devenv,
      ...
    }@inputs:

    let
      inputsWithLib = inputs // {
        env = import ./lib/env.nix;
        host = import ./lib/host.nix;
      };
    in
    flake-parts.lib.mkFlake { inputs = inputsWithLib; } (
      let
        inputs = inputsWithLib;
      in
      {
        systems = [
          "aarch64-darwin"
          "aarch64-linux"
          "x86_64-linux"
        ];

        imports = [
          treefmt-nix.flakeModule
          devenv.flakeModule
        ];

        flake =
          let
            mkDarwin =
              args:
              let
                darwin-modules = import ./hosts/darwin ({ inherit inputs; } // args);
              in
              inputs.nix-darwin.lib.darwinSystem {
                system = "aarch64-darwin";
                inherit (darwin-modules) specialArgs modules;
              };
          in
          {
            darwinConfigurations = {
              aarch64-darwin = mkDarwin { username = "shunkakinoki"; };
              runner = mkDarwin {
                isRunner = true;
                username = "runner";
              };
              galactica = import ./named-hosts/galactica {
                inherit inputs;
                username = "shunkakinoki";
              };
            };
            nixosConfigurations = {
              x86_64-linux = import ./hosts/nixos {
                inherit inputs;
                username = "shunkakinoki";
              };
              runner = import ./hosts/nixos {
                inherit inputs;
                isRunner = true;
